/**
 * @summary Import persons from CSV data
 */
export const getImportCsvPersonsUrl = () => {
  return `/api/csv/import`;
};

export const importCsvPersons = async (
  importCsvBody: ImportCsvBody,
  options?: RequestInit,
): Promise<ImportCsvResponse> => {
  return customFetch<ImportCsvResponse>(getImportCsvPersonsUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(importCsvBody),
  });
};

export const getImportCsvPersonsMutationOptions = <
  TError = ErrorType<UnauthorizedResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof importCsvPersons>>,
    TError,
    { data: BodyType<ImportCsvBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof importCsvPersons>>,
  TError,
  { data: BodyType<ImportCsvBody> },
  TContext
> => {
  const mutationKey = ["importCsvPersons"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof importCsvPersons>>,
    { data: BodyType<ImportCsvBody> }
  > = (props) => {
    const { data } = props ?? {};

    return importCsvPersons(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type ImportCsvPersonsMutationResult = NonNullable<
  Awaited<ReturnType<typeof importCsvPersons>>
>;
export type ImportCsvPersonsMutationBody = BodyType<ImportCsvBody>;
export type ImportCsvPersonsMutationError = ErrorType<UnauthorizedResponse>;

/**
 * @summary Import persons from CSV data
 */
export const useImportCsvPersons = <
  TError = ErrorType<UnauthorizedResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof importCsvPersons>>,
    TError,
    { data: BodyType<ImportCsvBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof importCsvPersons>>,
  TError,
  { data: BodyType<ImportCsvBody> },
  TContext
> => {
  return useMutation(getImportCsvPersonsMutationOptions(options));
};

